// Pull both ensures into context so triggers on `@` and `valid()` line up.
assert(r1@ == Seq::<K>::empty());
assert(r2@ == Seq::<K>::empty());
assert(r1.valid());
assert(r2.valid());

// Sequence extensionality lifts the two "== empty" facts to r1@ == r2@.
assert(r1@ =~= r2@);
assert(r1@ == r2@);
